 25	import Hostname from './Hostname/Hostname';
 26	import IP from './IP/IP';
 27	import Labels from './Labels/Labels';
 28	import Name from './Name/Name';
 29	import Namespace from './Namespace/Namespace';
 30	import Node from './Node/Node';
 31	import OperatingSystem from './OperatingSystem/OperatingSystem';
 32	import Pods from './Pods/Pods';
 33	import Timezone from './Timezone/Timezone';
 34	import WorkloadProfile from './WorkloadProfile/WorkloadProfile';
 35	
 36	type DetailsProps = {
 37	  pathname: string;
 38	  vmi: V1VirtualMachineInstance;
 39	};
 40	
 41	const Details: React.FC<DetailsProps> = ({ pathname, vmi }) => {
 42	  const { t } = useKubevirtTranslation();
 43	  const [guestAgentData, loadedGuestAgent] = useGuestOS(vmi);
 44	  const [vm] = useK8sWatchResource<V1VirtualMachine>({
 45	    groupVersionKind: VirtualMachineModelGroupVersionKind,
 46	    name: vmi?.metadata?.name,
 47	    namespace: vmi?.metadata?.namespace,
 48	  });
 49	  const [sshService, sshServiceLoaded] = useSSHService(vm);
 50	
 51	  return (
 52	    <div>
 53	      <a className="link-icon" href={`${pathname}#details`}>
 54	        <Icon size="sm">
 55	          <LinkIcon />
 56	        </Icon>
 57	      </a>
 58	      <Title className="co-section-heading" headingLevel="h2">
 59	        {t('VirtualMachineInstance Details')}
 60	      </Title>
 61	      <Grid hasGutter>
 62	        <GridItem span={5}>
 63	          <DescriptionList className="pf-v6-c-description-list">
 64	            <Name name={vmi?.metadata?.name} />
 65	            <Namespace namespace={vmi?.metadata?.namespace} />
 66	            <Labels vmi={vmi} />
 67	            <Annotations vmi={vmi} />
 68	            <Description vmi={vmi} />
 69	            <OperatingSystem
 70	              guestAgentData={guestAgentData}
 71	              loadedGuestAgent={loadedGuestAgent}
 72	              vmi={vmi}
 73	            />
 74	            <CPUMemory vmi={vmi} />
 75	            <VirtualMachineDescriptionItem
 76	              bodyContent={t('The QEMU machine type.')}
 77	              descriptionData={getMachineType(vm) || NO_DATA_DASH}
 78	              descriptionHeader={t('Machine type')}
 79	              isPopover
 80	            />
 81	            <CreateAt timestamp={vmi?.metadata?.creationTimestamp} />
 82	            <OwnerDetailsItem obj={vmi} />
 83	          </DescriptionList>
 84	        </GridItem>
 85	        <GridItem span={1}></GridItem>
 86	        <GridItem span={5}>
 87	          <DescriptionList className="pf-v6-c-description-list">
 88	            <VirtualMachineDescriptionItem
 89	              descriptionData={<VirtualMachinesInstancesStatus status={vmi?.status?.phase} />}
 90	              descriptionHeader={t('Status')}
 91	            />
 92	            <VirtualMachineDescriptionItem
 93	              descriptionData={<Pods vmi={vmi} />}
 94	              descriptionHeader={t('Pod')}
 95	            />
 96	            <VirtualMachineDescriptionItem
 97	              descriptionData={
 98	                <BootOrder
 99	                  disks={vmi?.spec?.domain?.devices?.disks}
100	                  interfaces={vmi?.spec?.domain?.devices?.interfaces}
101	                />
102	              }
103	              descriptionHeader={t('Boot order')}
104	            />
105	            <VirtualMachineDescriptionItem
106	              descriptionData={<IP vmi={vmi} />}
107	              descriptionHeader={t('IP address')}
108	            />
109	            <VirtualMachineDescriptionItem
110	              descriptionData={<Hostname guestAgentData={guestAgentData} />}
111	              descriptionHeader={'Hostname'}
112	            />
113	            <VirtualMachineDescriptionItem
114	              descriptionData={<Timezone guestAgentData={guestAgentData} />}
115	              descriptionHeader={t('Time zone')}
116	            />
117	            <VirtualMachineDescriptionItem
118	              descriptionData={<Node nodeName={vmi?.status?.nodeName} />}
119	              descriptionHeader={t('Node')}
120	            />
121	            <VirtualMachineDescriptionItem
122	              descriptionData={<WorkloadProfile annotations={vmi?.metadata?.annotations} />}
123	              descriptionHeader={t('Workload profile')}
124	            />
125	            <VirtualMachineDescriptionItem
126	              descriptionData={
127	                <SSHAccess sshService={sshService} sshServiceLoaded={sshServiceLoaded} vm={vm} />
128	              }
129	              descriptionHeader={t('SSH access')}
130	            />
131	            <VirtualMachineDescriptionItem
132	              descriptionData={<HardwareDevices devices={vmi?.spec?.domain?.devices} />}
133	              descriptionHeader={t('Hardware devices')}
134	            />
135	          </DescriptionList>
136	        </GridItem>
137	      </Grid>
138	    </div>
139	  );
140	};
141	
142	export default Details;

